import socket
import json
import threading

class GameServer:
    def __init__(self, host='0.0.0.0', port=12345):
        self.server_address = (host, port)
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.bind(self.server_address)
        self.players = []
        self.game_state = {
            'status': 'running',
            'current_level': 'level_1',
            'time_left': 300
        }
        self.lock = threading.Lock()

    def add_player(self, player_name):
        with self.lock:
            self.players.append(player_name)

    def remove_player(self, player_name):
        with self.lock:
            if player_name in self.players:
                self.players.remove(player_name)

    def get_status(self):
        with self.lock:
            return {
                'players': self.players,
                'game_state': self.game_state
            }

    def handle_request(self, data, addr):
        if data.decode('utf-8') == "server_status":
            response_data = json.dumps(self.get_status())
            self.sock.sendto(response_data.encode('utf-8'), addr)

    def run(self):
        print(f'Server listening on {self.server_address}')
        while True:
            data, addr = self.sock.recvfrom(4096)
            threading.Thread(target=self.handle_request, args=(data, addr)).start()

if __name__ == '__main__':
    server = GameServer()
    threading.Thread(target=server.run).start()